import{_ as a,o as t,c as n,a4 as i}from"./chunks/framework.BjA-8Gni.js";const p=JSON.parse('{"title":"ADR-005: A single canonical sanitize injection boundary","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-005-sanitize-boundary.md","filePath":"reference/decisions/ADR-005-sanitize-boundary.md"}'),o={name:"reference/decisions/ADR-005-sanitize-boundary.md"};function s(r,e,l,c,d,u){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-005-a-single-canonical-sanitize-injection-boundary" tabindex="-1">ADR-005: A single canonical sanitize injection boundary <a class="header-anchor" href="#adr-005-a-single-canonical-sanitize-injection-boundary" aria-label="Permalink to &quot;ADR-005: A single canonical sanitize injection boundary&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-08 (essentials gate, logging, errors &amp; security)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Untrusted text — user input, file contents, network data an app chooses to display — can contain control bytes and escape sequences. If such bytes reach the terminal as live cells, they can move the cursor, change modes, or inject sequences (a terminal injection attack). The engine needs a guaranteed point where this can never happen.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-sanitize-at-each-draw-call-site-ad-hoc" tabindex="-1">Option A: Sanitize at each draw call site, ad-hoc <a class="header-anchor" href="#option-a-sanitize-at-each-draw-call-site-ad-hoc" aria-label="Permalink to &quot;Option A: Sanitize at each draw call site, ad-hoc&quot;">​</a></h3><ul><li><strong>Pros</strong>: Localized.</li><li><strong>Cons</strong>: Easy to forget one path; inconsistent rules; no single guarantee.</li></ul><h3 id="option-b-one-canonical-sanitize-boundary-that-all-text-crosses" tabindex="-1">Option B: One canonical <code>sanitize</code> boundary that all text crosses <a class="header-anchor" href="#option-b-one-canonical-sanitize-boundary-that-all-text-crosses" aria-label="Permalink to &quot;Option B: One canonical `sanitize` boundary that all text crosses&quot;">​</a></h3><ul><li><strong>Pros</strong>: A single, audited choke point; <code>ScreenBuffer.text</code> (and any text→cell path) routes through it, so control bytes never become cells; one place to reason about and test the rules.</li><li><strong>Cons</strong>: Must ensure every text→cell path actually goes through it.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — <code>sanitize</code> (exported from <code>safety/</code>) is the single canonical injection boundary; all untrusted text becomes cells only after passing through it.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Concentrating the rule in one function makes the security property auditable and testable in isolation: control bytes are stripped before they can be serialized into escape sequences (RD-04 AC-8). Because <code>ScreenBuffer.text</code> sanitizes its input, an app cannot accidentally bypass the boundary by drawing untrusted strings. Capability responses are handled with the same untrusted-data posture (bounded, parsed as data only).</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>A single, audited injection choke point; testable in isolation.</li><li>Apps get injection safety by default when drawing text.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Every new text→cell path must be routed through <code>sanitize</code> (enforced by review).</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A future direct cell-write API could bypass the boundary — such APIs must document that they take pre-sanitized input or sanitize internally.</li></ul>',20)])])}const b=a(o,[["render",s]]);export{p as __pageData,b as default};
